"""
Sales Analysis Engine using MongoDB Aggregation Pipelines
Identifies top-performing products by category within a specified date range.
"""

from datetime import datetime
from typing import Dict, List
from pymongo import MongoClient
from pymongo.database import Database


class SalesAnalyzer:
    """
    A robust sales analysis engine for high-volume e-commerce platforms.

    Analyzes product performance by total revenue (price * quantity) within a date range
    and groups results by category with multi-level sorting.
    """

    def __init__(self, db_url: str, db_name: str) -> None:
        """
        Initialize the SalesAnalyzer with database connection.

        Args:
            db_url: MongoDB connection string (e.g., "mongodb://localhost:27017")
            db_name: Name of the target database
        """
        self.client: MongoClient = MongoClient(db_url)
        self.db: Database = self.client[db_name]

    def get_top_performing_products(
        self, start_date: str, end_date: str, limit: int = 3
    ) -> Dict[str, List[Dict]]:
        """
        Retrieve top-performing products grouped by category within a date range.

        Performance is measured by total revenue (price * quantity). Products are ranked
        within each category by:
        1. Total Revenue (Descending)
        2. Total Quantity (Descending)
        3. Product ID (Ascending) - for deterministic tie-breaking

        Args:
            start_date: ISO 8601 format start date (inclusive)
            end_date: ISO 8601 format end date (inclusive)
            limit: Maximum number of products per category to return (default: 3)

        Returns:
            Dictionary where:
            - Keys: Category names (str)
            - Values: List of product dicts with keys:
              - product_id (int)
              - product_name (str)
              - total_revenue (float, rounded to 2 decimals)
              - total_quantity (int)
        """
        # Parse dates to ensure they are proper datetime objects
        start_dt: datetime = datetime.fromisoformat(start_date.replace('Z', '+00:00'))
        end_dt: datetime = datetime.fromisoformat(end_date.replace('Z', '+00:00'))

        # Reference collections
        orders_collection = self.db['orders']
        products_collection = self.db['products']

        # Build the aggregation pipeline
        pipeline: List[Dict] = [
            # Stage 1: Filter orders within the date range (inclusive)
            {
                "$match": {
                    "date": {
                        "$gte": start_dt,
                        "$lte": end_dt
                    }
                }
            },
            # Stage 2: Join with products collection to get category and price
            {
                "$lookup": {
                    "from": "products",
                    "localField": "product_id",
                    "foreignField": "product_id",
                    "as": "product_info"
                }
            },
            # Stage 3: Unwind product_info; exclude orders with no matching product
            {
                "$unwind": {
                    "path": "$product_info",
                    "preserveNullAndEmptyArrays": False
                }
            },
            # Stage 4: Calculate revenue for each order (price * quantity)
            {
                "$project": {
                    "product_id": "$product_info.product_id",
                    "product_name": "$product_info.product_name",
                    "category": "$product_info.category",
                    "price": "$product_info.price",
                    "quantity": "$quantity",
                    "revenue": {
                        "$multiply": ["$product_info.price", "$quantity"]
                    }
                }
            },
            # Stage 5: Group by product to calculate total revenue and quantity
            {
                "$group": {
                    "_id": {
                        "product_id": "$product_id",
                        "product_name": "$product_name",
                        "category": "$category"
                    },
                    "total_revenue": {
                        "$sum": "$revenue"
                    },
                    "total_quantity": {
                        "$sum": "$quantity"
                    }
                }
            },
            # Stage 6: Restructure the document for easier processing
            {
                "$project": {
                    "_id": 0,
                    "product_id": "$_id.product_id",
                    "product_name": "$_id.product_name",
                    "category": "$_id.category",
                    "total_revenue": {
                        "$round": ["$total_revenue", 2]
                    },
                    "total_quantity": "$total_quantity"
                }
            },
            # Stage 7: Sort by category, then by revenue (desc), quantity (desc), product_id (asc)
            {
                "$sort": {
                    "category": 1,
                    "total_revenue": -1,
                    "total_quantity": -1,
                    "product_id": 1
                }
            },
            # Stage 8: Group by category and collect products with limit
            {
                "$group": {
                    "_id": "$category",
                    "products": {
                        "$push": {
                            "product_id": "$product_id",
                            "product_name": "$product_name",
                            "total_revenue": "$total_revenue",
                            "total_quantity": "$total_quantity"
                        }
                    }
                }
            },
            # Stage 9: Apply limit per category
            {
                "$project": {
                    "_id": 0,
                    "category": "$_id",
                    "products": {
                        "$slice": ["$products", limit]
                    }
                }
            },
            # Stage 10: Sort categories alphabetically for consistent output
            {
                "$sort": {
                    "category": 1
                }
            }
        ]

        # Execute the aggregation pipeline
        try:
            results = list(orders_collection.aggregate(pipeline))
        except Exception:
            # If aggregation fails (e.g., empty collections), return empty dict
            return {}

        # Transform results into the required output format
        output: Dict[str, List[Dict]] = {}
        for result in results:
            category = result["category"]
            products = result["products"]
            output[category] = products

        return output

    def close(self) -> None:
        """Close the database connection."""
        self.client.close()

